const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const parseCellKey = (k: string): Cell => {
  const [x, y] = k.split(",").map(Number);
  return [x, y];
};

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveSet = new Set(cells.map(cellKey));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const k = cellKey([x + dx, y + dy]);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  const isAliveNextGen = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveSet.has(k));

  const nextCells: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    if (isAliveNextGen(k, count)) nextCells.push(parseCellKey(k));
  }
  return nextCells;
};

