const cellKey = ([x, y]: Cell): string => `${x},${y}`;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveSet = new Set(cells.map(cellKey));

  const neighbors = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = cellKey(cell);
      const entry = neighbors.get(k);
      if (entry) entry.count++;
      else neighbors.set(k, { cell, count: 1 });
    }
  }

  const isAliveNextGen = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveSet.has(k));

  const nextCells: Cell[] = [];
  for (const [k, { cell, count }] of neighbors) {
    if (isAliveNextGen(k, count)) nextCells.push(cell);
  }
  return nextCells;
};
